#![no_std]
#![no_main]
#![doc = include_str!("../README.md")]

extern crate alloc;
#[macro_use]
extern crate axlog;

pub mod entry;
mod mm;
mod syscall;

use alloc::string::{String, ToString};
use alloc::vec;
use alloc::vec::Vec;
use axdisplay::get_main_display;
use axfs_ng::api::FS_CONTEXT;

use axdriver_display::DisplayDriverOps;
use axhal::mem::VirtAddr;
use axmm::kernel_aspace;
use entry::run_user_app;
use undefined_os_api::core::file::fd::{FD_TABLE, FdTable};
use undefined_os_api::core::fs::mount::mount_all;

#[unsafe(no_mangle)]
fn main() {
    let root_dir = axfs_ng::api::FS_CONTEXT.lock().root_dir.clone();
    FS_CONTEXT.lock().change_root(root_dir).unwrap();
    FD_TABLE.init_new(FdTable::new());
    mount_all().expect("Mounting all filesystems failed");

    let command = include_str!(env!("AX_TESTCASES_FILE"));
    let args = vec!["/musl/busybox", "sh", "-c", command];
    let args: Vec<String> = args.into_iter().map(String::from).collect();

    let envs = vec![
        "PATH=/bin".to_string(),
        // "LD_LIBRARY_PATH=/lib:/lib64".to_string(),
        // "LD_DEBUG=all".to_string(),
    ];

    let exit_code = run_user_app(&args, &envs);
    info!("[task manager] Shell exited with code: {:?}", exit_code);
}

use alloc::{string::String, sync::Arc};
use axfs_ng::api::{FS_CONTEXT, resolve_path};
use axhal::arch::UspaceContext;
use axsignal::Signo;
use spin::Mutex;
use starry_core::mm::{copy_from_kernel, load_user_app, map_trampoline, new_user_aspace_empty};
use starry_core::process::{ProcessData, create_thread_data};
use starry_core::task::{TaskExt, create_user_task};
use undefined_os_api::core::file::fd::FD_TABLE;
use undefined_process::process::Process;

pub fn run_user_app(args: &[String], envs: &[String]) -> Option<i32> {
    // create user address space
    // to hold executable file and other data
    let mut uspace = new_user_aspace_empty()
        .and_then(|mut it| {
            copy_from_kernel(&mut it)?;
            // signal trampoline
            map_trampoline(&mut it)?;
            Ok(it)
        })
        .expect("Failed to create user address space");

    // set current directory
    let mut context = FS_CONTEXT.lock();
    let path =
        resolve_path(&context, &args[0], &mut 0, false).expect("Failed to resolve file path");
    context
        .change_dir(path.parent().unwrap())
        .expect("Failed to set current dir");
    drop(context);

    // load executable file
    let (entry_vaddr, ustack_top) = load_user_app(&mut uspace, args, envs)
        .unwrap_or_else(|e| panic!("Failed to load user app: {}", e));

    // create user context
    let uctx = UspaceContext::new(entry_vaddr.into(), ustack_top, 2333);
    // create user task for scheduler
    let mut user_task = create_user_task(args.join(" "), uctx);
    user_task
        .ctx_mut()
        .set_page_table_root(uspace.page_table_root());

    // create thread
    let process = Process::spawn_process();
    let thread = process.get_main_thread().unwrap();

    // init task extended data
    let process_data = ProcessData::new(
        args.to_vec(),
        Arc::new(Mutex::new(uspace)),
        Arc::default(),
        Some(Signo::SIGCHLD),
    );
    let thread_data = create_thread_data(Arc::new(process_data), thread.get_tid());

    FD_TABLE
        .deref_from(&thread_data.namespace)
        .init_new(FD_TABLE.copy_inner());
    FS_CONTEXT
        .deref_from(&thread_data.namespace)
        .init_new(FS_CONTEXT.copy_inner());

    user_task.init_task_ext(TaskExt::new(thread, thread_data));

    // spawn and wait the task
    let user_task = axtask::spawn_task(user_task);
    user_task.join()
}

use arceos_posix_api::config::plat::PHYS_VIRT_OFFSET;
use axerrno::LinuxError;
use axhal::mem::VirtAddr;
use axhal::paging::MappingFlags;
use axhal::trap::{PAGE_FAULT, register_trap_handler};
use axsignal::{SignalInfo, Signo};
use linux_raw_sys::general::SI_KERNEL;
use starry_core::mm::is_accessing_user_memory;
use starry_core::task::{current_process, current_process_data};
use undefined_os_api::imp::task::signal::send_signal_process;
use undefined_os_api::imp::task::sys_exit_impl;

#[register_trap_handler(PAGE_FAULT)]
fn handle_page_fault(vaddr: VirtAddr, access_flags: MappingFlags, is_user: bool) -> bool {
    if vaddr.as_usize() > PHYS_VIRT_OFFSET {
        error!(
            "Kernel page fault at {:#x}, access_flags: {:#x?}",
            vaddr, access_flags
        );
        return false;
    }
    if !is_user && !is_accessing_user_memory() {
        warn!(
            "Maybe we are accessing user memory in kernel, and triggered a page fault at {:#x}, access_flags: {:#x?}",
            vaddr, access_flags
        );
    }

    if !current_process_data()
        .addr_space
        .lock()
        .handle_page_fault(vaddr, access_flags)
    {
        warn!(
            "{}: segmentation fault at {:#x}, access_flags: {:#x?}, send SIGSEGV.",
            axtask::current().id_name(),
            vaddr,
            access_flags,
        );
        if send_signal_process(
            current_process().get_pid(),
            SignalInfo::new(Signo::SIGSEGV, SI_KERNEL as _),
        )
        .is_err()
        {
            error!("send SIGSEGV failed");
            sys_exit_impl(LinuxError::EFAULT as _, Signo::SIGSEGV as _, false);
        }
    }
    true
}

#![no_std]

