/// Task extended data for the monolithic kernel.
pub struct TaskExt {
    /// The time statistics.
    pub time: RefCell<TimeStat>,
    /// The POSIX thread corresponding to this task.
    pub thread: Arc<Thread>,
    /// The thread data bind to this task.
    pub thread_data: Arc<ThreadData>,
}

pub fn current_thread() -> Arc<Thread> {
    current().task_ext().thread.clone()
}

pub fn current_thread_data() -> Arc<ThreadData> {
    current().task_ext().thread_data.clone()
}

pub fn current_process() -> Arc<Process> {
    current_thread().get_process()
}

pub fn current_process_data() -> Arc<ProcessData> {
    current_thread_data().process_data.clone()
}

impl TaskExt {
    pub fn new(thread: Arc<Thread>, thread_data: Arc<ThreadData>) -> Self {
        Self {
            time: TimeStat::new().into(),
            thread,
            thread_data,
        }
    }

    pub(crate) fn time_stat_from_kernel_to_user(&self, current_tick: usize) {
        self.time.borrow_mut().switch_into_user_mode(current_tick);
    }

    pub(crate) fn time_stat_from_user_to_kernel(&self, current_tick: usize) {
        self.time.borrow_mut().switch_into_kernel_mode(current_tick);
    }

    pub(crate) fn time_stat_output(&self) -> (usize, usize) {
        self.time.borrow().output()
    }
}

struct AxNamespaceImpl;
#[crate_interface::impl_interface]
impl AxNamespaceIf for AxNamespaceImpl {
    fn current_namespace_base() -> *mut u8 {
        // Namespace for kernel task
        static KERNEL_NS_BASE: Once<usize> = Once::new();
        let current = axtask::current();
        // Safety: We only check whether the task extended data is null and do not access it.
        if unsafe { current.task_ext_ptr() }.is_null() {
            return *(KERNEL_NS_BASE.call_once(|| {
                let global_ns = AxNamespace::global();
                let layout = Layout::from_size_align(global_ns.size(), 64).unwrap();
                // Safety: The global namespace is a static readonly variable and will not be dropped.
                let dst = unsafe { alloc::alloc::alloc(layout) };
                let src = global_ns.base();
                unsafe { core::ptr::copy_nonoverlapping(src, dst, global_ns.size()) };
                dst as usize
            })) as *mut u8;
        }
        current_thread_data().namespace.base()
    }
}

impl Drop for TaskExt {
    fn drop(&mut self) {
        trace!("TaskExt drop.");
    }
}

axtask::def_task_ext!(TaskExt);

#[allow(unused)]
pub fn write_trapframe_to_kstack(kstack_top: usize, trap_frame: &TrapFrame) {
    let trap_frame_size = core::mem::size_of::<TrapFrame>();
    let trap_frame_ptr = (kstack_top - trap_frame_size) as *mut TrapFrame;
    unsafe {
        *trap_frame_ptr = *trap_frame;
    }
}

pub fn read_trapframe_from_kstack(kstack_top: usize) -> TrapFrame {
    let trap_frame_size = core::mem::size_of::<TrapFrame>();
    let trap_frame_ptr = (kstack_top - trap_frame_size) as *mut TrapFrame;
    unsafe { *trap_frame_ptr }
}

pub fn time_stat_from_kernel_to_user() {
    let curr_task = current();
    curr_task
        .task_ext()
        .time_stat_from_kernel_to_user(monotonic_time_nanos() as usize);
}

pub fn time_stat_from_user_to_kernel() {
    let curr_task = current();
    curr_task
        .task_ext()
        .time_stat_from_user_to_kernel(monotonic_time_nanos() as usize);
}

pub fn time_stat_output() -> (usize, usize, usize, usize) {
    let curr_task = current();
    let (utime_ns, stime_ns) = curr_task.task_ext().time_stat_output();
    (
        utime_ns / NANOS_PER_SEC as usize,
        utime_ns / NANOS_PER_MICROS as usize,
        stime_ns / NANOS_PER_SEC as usize,
        stime_ns / NANOS_PER_MICROS as usize,
    )
}

pub fn create_user_task(name: String, uctx: UspaceContext) -> TaskInner {
    let name = name.chars().take(32).collect();
    TaskInner::new(
        move || {
            let curr = current();
            let kstack_top = curr.kernel_stack_top().unwrap();
            info!(
                "Enter user space: entry={:#x}, ustack={:#x}, kstack={:#x}",
                uctx.ip(),
                uctx.sp(),
                kstack_top,
            );

            // Set the tid into address `set_child_tid`:
            // When `set_child_tid` is set, the very first thing
            // the new thread does is to write its thread ID at this address.
            let addr = current_thread_data()
                .addr_set_child_tid
                .load(Ordering::Relaxed);
            // TODO: user UserPtr wrapper to check it
            // however, UserPtr is not defined in current crate
            let addr: *mut u32 = addr as _;
            info!("set_child_tid={:#x}", addr.addr());
            if !addr.is_null() {
                unsafe { addr.write(current_thread().get_tid()) };
            }

            unsafe { uctx.enter_uspace(kstack_top) }
        },
        name,
        axconfig::plat::KERNEL_STACK_SIZE,
    )
}

#[doc(hidden)]
pub struct WaitQueueWrapper(WaitQueue);
impl Default for WaitQueueWrapper {
    fn default() -> Self {
        Self(WaitQueue::new())
    }
}
impl axsignal::api::WaitQueue for WaitQueueWrapper {
    fn wait_timeout(&self, timeout: Option<Duration>) -> bool {
        if let Some(timeout) = timeout {
            self.0.wait_timeout(timeout, false)
        } else {
            self.0.wait();
            true
        }
    }

    fn notify_one(&self) -> bool {
        self.0.notify_one(false)
    }
}

use core::ffi::CStr;

use alloc::string::ToString;
use alloc::{string::String, vec};
use axerrno::{AxError, AxResult, LinuxError, LinuxResult};
use axfs_ng::api::FS_CONTEXT;
use axhal::mem::virt_to_phys;
use axhal::paging::{MappingFlags, PageSize};
use axmm::{AddrSpace, kernel_aspace};
use kernel_elf_parser::{AuxvEntry, ELFParser, app_stack_region};
use memory_addr::{MemoryAddr, PAGE_SIZE_4K, VirtAddr};
use xmas_elf::{ElfFile, program::SegmentData};

pub fn new_user_aspace_empty() -> AxResult<AddrSpace> {
    AddrSpace::new_empty(
        VirtAddr::from_usize(axconfig::plat::USER_SPACE_BASE),
        axconfig::plat::USER_SPACE_SIZE,
    )
}

/// If the target architecture requires it, the kernel portion of the address
/// space will be copied to the user address space.
pub fn copy_from_kernel(aspace: &mut AddrSpace) -> AxResult {
    #[cfg(not(any(target_arch = "aarch64", target_arch = "loongarch64")))]
    {
        // ARMv8 (aarch64) and LoongArch64 use separate page tables for user space
        // (aarch64: TTBR0_EL1, LoongArch64: PGDL), so there is no need to copy the
        // kernel portion to the user page table.
        aspace.copy_mappings_from(&kernel_aspace().lock())?;
    }
    Ok(())
}

/// Map the signal trampoline to the user address space.
pub fn map_trampoline(aspace: &mut AddrSpace) -> AxResult {
    let signal_trampoline_paddr = virt_to_phys(axsignal::arch::signal_trampoline_address().into());
    aspace.map_linear(
        axconfig::plat::SIGNAL_TRAMPOLINE.into(),
        signal_trampoline_paddr,
        PAGE_SIZE_4K,
        MappingFlags::READ | MappingFlags::EXECUTE | MappingFlags::USER,
        PageSize::Size4K,
    )?;
    Ok(())
}

/// Map the elf file to the user address space.
///
/// # Arguments
/// - `uspace`: The address space of the user app.
/// - `elf`: The elf file.
///
/// # Returns
/// - The entry point of the user app.
fn map_elf(uspace: &mut AddrSpace, elf: &ElfFile) -> AxResult<(VirtAddr, [AuxvEntry; 17])> {
    let uspace_base = uspace.base().as_usize();
    let elf_parser = ELFParser::new(
        elf,
        axconfig::plat::USER_INTERP_BASE,
        Some(uspace_base as isize),
        uspace_base,
    )
    .map_err(|_| AxError::InvalidData)?;

    for segment in elf_parser.ph_load() {
        debug!(
            "Mapping ELF segment: [{:#x?}, {:#x?}) flags: {:#x?}",
            segment.vaddr,
            segment.vaddr + segment.memsz as usize,
            segment.flags
        );
        let seg_pad = segment.vaddr.align_offset_4k();
        assert_eq!(seg_pad, segment.offset % PAGE_SIZE_4K);

        let seg_align_size =
            (segment.memsz as usize + seg_pad + PAGE_SIZE_4K - 1) & !(PAGE_SIZE_4K - 1);
        uspace.map_alloc(
            segment.vaddr.align_down_4k(),
            seg_align_size,
            segment.flags,
            true,
            PageSize::Size4K,
        )?;
        let seg_data = elf
            .input
            .get(segment.offset..segment.offset + segment.filesz as usize)
            .ok_or(AxError::InvalidData)?;
        uspace.write(segment.vaddr, PageSize::Size4K, seg_data)?;
        // TDOO: flush the I-cache
    }

    Ok((
        elf_parser.entry().into(),
        elf_parser.auxv_vector(PAGE_SIZE_4K),
    ))
}

/// Load the user app to the user address space.
///
/// # Arguments
/// - `uspace`: The address space of the user app.
/// - `args`: The arguments of the user app. The first argument is the path of the user app.
/// - `envs`: The environment variables of the user app.
///
/// # Returns
/// - The entry point of the user app.
/// - The stack pointer of the user app.
pub fn load_user_app(
    uspace: &mut AddrSpace,
    args: &[String],
    envs: &[String],
) -> LinuxResult<(VirtAddr, VirtAddr)> {
    if args.is_empty() {
        return Err(LinuxError::EINVAL);
    }
    let context = FS_CONTEXT.lock();
    let path = args[0].as_str();
    let file_data = context.read(path).inspect_err(|_| {
        error!("Load user app could not read file: {}", path);
    })?;
    drop(context);
    let elf = if let Ok(elf) = ElfFile::new(&file_data) {
        elf
    } else {
        // Not a valid ELF file, maybe a script file.
        if file_data.starts_with(b"#!") {
            // A script file, try to read the interpreter path.
            let first_line_end = file_data
                .iter()
                .position(|&c| c == b'\n')
                .unwrap_or(file_data.len());
            let first_line = &file_data[2..first_line_end];
            let interp_path = core::str::from_utf8(first_line)
                .map_err(|_| LinuxError::EINVAL)?
                .trim();
            let mut new_args = vec![interp_path.to_string()];
            new_args.extend_from_slice(args);
            return load_user_app(uspace, &new_args, envs);
        } else {
            error!("Load user app invalid ELF file: {}", path);
            return Err(LinuxError::ENOEXEC);
        }
    };

    if let Some(interp) = elf
        .program_iter()
        .find(|ph| ph.get_type() == Ok(xmas_elf::program::Type::Interp))
    {
        let interp = match interp.get_data(&elf) {
            Ok(SegmentData::Undefined(data)) => data,
            _ => panic!("Invalid data in Interp Elf Program Header"),
        };

        let interp_path = CStr::from_bytes_with_nul(interp)
            .map_err(|_| AxError::InvalidData)?
            .to_str()
            .map_err(|_| AxError::InvalidData)?
            .to_string();

        // Set the first argument to the path of the user app.
        let mut new_args = vec![interp_path];
        new_args.extend_from_slice(args);
        return load_user_app(uspace, &new_args, envs);
    }

    let (entry, mut auxv) = map_elf(uspace, &elf)?;
    // The user stack is divided into two parts:
    // `ustack_start` -> `ustack_pointer`: It is the stack space that users actually read and write.
    // `ustack_pointer` -> `ustack_end`: It is the space that contains the arguments, environment variables and auxv passed to the app.
    //  When the app starts running, the stack pointer points to `ustack_pointer`.
    let ustack_end = VirtAddr::from_usize(axconfig::plat::USER_STACK_TOP);
    let ustack_size = axconfig::plat::USER_STACK_SIZE;
    let ustack_start = ustack_end - ustack_size;
    debug!(
        "Mapping user stack: {:#x?} -> {:#x?}",
        ustack_start, ustack_end
    );

    let stack_data = app_stack_region(args, envs, &mut auxv, ustack_start, ustack_size);
    uspace.map_alloc(
        ustack_start,
        ustack_size,
        MappingFlags::READ | MappingFlags::WRITE | MappingFlags::USER,
        true,
        PageSize::Size4K,
    )?;

    let heap_start = VirtAddr::from_usize(axconfig::plat::USER_HEAP_BASE);
    let heap_size = axconfig::plat::USER_HEAP_SIZE;
    uspace.map_alloc(
        heap_start,
        heap_size,
        MappingFlags::READ | MappingFlags::WRITE | MappingFlags::USER,
        true,
        PageSize::Size4K,
    )?;

    let user_sp = ustack_end - stack_data.len();

    assert!(user_sp.is_aligned(16usize), "user sp is not aligned to 16");

    uspace.write(user_sp, PageSize::Size4K, stack_data.as_slice())?;

    debug!("entry: {:#x?}  sp:: {:#x?}", entry, user_sp);

    Ok((entry, user_sp))
}

#[percpu::def_percpu]
static mut ACCESSING_USER_MEM: bool = false;

/// Enables scoped access into user memory, allowing page faults to occur inside
/// kernel.
pub fn access_user_memory<R>(f: impl FnOnce() -> R) -> R {
    ACCESSING_USER_MEM.with_current(|v| {
        *v = true;
        let result = f();
        *v = false;
        result
    })
}

/// Check if the current thread is accessing user memory.
pub fn is_accessing_user_memory() -> bool {
    ACCESSING_USER_MEM.read_current()
}

use linux_raw_sys::general::{
    RLIM_INFINITY, RLIM_NLIMITS, RLIMIT_AS, RLIMIT_CORE, RLIMIT_CPU, RLIMIT_DATA, RLIMIT_FSIZE,
    RLIMIT_LOCKS, RLIMIT_MEMLOCK, RLIMIT_MSGQUEUE, RLIMIT_NICE, RLIMIT_NOFILE, RLIMIT_NPROC,
    RLIMIT_RSS, RLIMIT_RTPRIO, RLIMIT_RTTIME, RLIMIT_SIGPENDING, RLIMIT_STACK,
};
use num_enum::TryFromPrimitive;

// hard limits
// TODO: make them configurable
/// hard limit for `RLIMIT_NOFILE`
pub const RLIMIT_MAX_FILES: usize = 1024;

pub const RLIMIT_INFINITY: u64 = u64::MAX;
const _: () = assert!(RLIMIT_INFINITY == RLIM_INFINITY as i64 as u64);

#[repr(u32)]
#[derive(TryFromPrimitive, Clone, Copy, Debug)]
pub enum ResourceLimitType {
    CPU = RLIMIT_CPU,
    FSIZE = RLIMIT_FSIZE,
    DATA = RLIMIT_DATA,
    STACK = RLIMIT_STACK,
    CORE = RLIMIT_CORE,
    RSS = RLIMIT_RSS,
    NPROC = RLIMIT_NPROC,
    NOFILE = RLIMIT_NOFILE,
    MEMLOCK = RLIMIT_MEMLOCK,
    AS = RLIMIT_AS,
    LOCKS = RLIMIT_LOCKS,
    SIGPENDING = RLIMIT_SIGPENDING,
    MSGQUEUE = RLIMIT_MSGQUEUE,
    NICE = RLIMIT_NICE,
    RTPRIO = RLIMIT_RTPRIO,
    RTTIME = RLIMIT_RTTIME,
}

impl ResourceLimitType {
    pub fn to_usize(self: &Self) -> usize {
        *self as usize
    }
}

#[repr(C)]
#[derive(Clone, Copy, Default, Debug)]
pub struct ResourceLimit {
    pub soft: u64,
    pub hard: u64,
}

impl ResourceLimit {
    /// Create a new ResourceLimit with the same values as the given limit
    pub fn new(soft: u64, hard: u64) -> Self {
        Self { soft, hard }
    }

    /// Create a new ResourceLimit with infinite values
    pub fn new_infinite() -> Self {
        Self {
            soft: RLIMIT_INFINITY,
            hard: RLIMIT_INFINITY,
        }
    }
}

pub struct ResourceLimits([ResourceLimit; RLIM_NLIMITS as usize]);

impl ResourceLimits {
    pub fn new() -> Self {
        let mut limits = [ResourceLimit::new_infinite(); RLIM_NLIMITS as usize];
        limits[ResourceLimitType::STACK as usize] =
            ResourceLimit::new(axconfig::plat::USER_STACK_SIZE as u64, RLIMIT_INFINITY);
        limits[ResourceLimitType::CORE as usize] = ResourceLimit::new(0, RLIMIT_INFINITY);
        limits[ResourceLimitType::NPROC as usize] = ResourceLimit::new(10000, 10000);
        limits[ResourceLimitType::NOFILE as usize] =
            ResourceLimit::new(1024, RLIMIT_MAX_FILES as _);
        Self(limits)
    }

    pub fn get_soft(&self, resource: &ResourceLimitType) -> u64 {
        self.0[*resource as usize].soft
    }

    pub fn get(&self, resource: &ResourceLimitType) -> ResourceLimit {
        self.0[*resource as usize].clone()
    }

    pub fn set(&mut self, resource: &ResourceLimitType, limit: ResourceLimit) -> bool {
        if limit.soft > limit.hard {
            return false;
        }
        self.0[*resource as usize] = limit;
        true
    }
}

use alloc::collections::BTreeMap;
use alloc::sync::Arc;
use axalloc::global_allocator;
use axerrno::{LinuxError, LinuxResult};
use axsync::Mutex;
use core::sync::atomic::{AtomicU32, Ordering};
use memory_addr::PAGE_SIZE_4K;

#[derive(Debug)]
pub struct SharedMemory {
    /// The key of the shared memory segment
    pub key: u32,
    /// Virtual kernel address of the shared memory segment
    pub addr: usize,
    /// Page count of the shared memory segment
    pub page_count: usize,
}

impl Drop for SharedMemory {
    fn drop(&mut self) {
        let allocator = global_allocator();
        allocator.dealloc_pages(self.addr, self.page_count);
        info!(
            "[SharedMemory] dealloc pages: addr: {:#x}, page_count: {}, key: {}",
            self.addr, self.page_count, self.key
        );
    }
}

pub struct SharedMemoryManager {
    pub mem_map: Mutex<BTreeMap<u32, Arc<SharedMemory>>>,
    next_key: AtomicU32,
}

impl SharedMemoryManager {
    pub const fn new() -> Self {
        SharedMemoryManager {
            mem_map: Mutex::new(BTreeMap::new()),
            next_key: AtomicU32::new(1),
        }
    }

    pub fn next_available_key(&self) -> u32 {
        let next_key = self.next_key.fetch_add(1, Ordering::Relaxed);
        self.mem_map.lock().keys().max().unwrap_or(&0) + next_key
    }

    pub fn get(&self, key: u32) -> Option<Arc<SharedMemory>> {
        self.mem_map.lock().get(&key).cloned()
    }

    pub fn create(&self, key: u32, size: usize) -> LinuxResult<Arc<SharedMemory>> {
        let page_count = size.div_ceil(PAGE_SIZE_4K);
        let allocator = global_allocator();
        // TODO: more error checking
        let vaddr = allocator
            .alloc_pages(page_count, PAGE_SIZE_4K)
            .map_err(|_| LinuxError::ENOMEM)?;
        let shared_memory = SharedMemory {
            key,
            addr: vaddr,
            page_count,
        };
        let shared_memory = Arc::new(shared_memory);
        self.mem_map.lock().insert(key, shared_memory.clone());
        Ok(shared_memory)
    }

    pub fn delete(&self, key: u32) -> bool {
        self.mem_map.lock().remove(&key).is_some()
    }
}

pub static SHARED_MEMORY_MANAGER: SharedMemoryManager = SharedMemoryManager::new();

use crate::Pid;
use crate::process_group::{ProcessGroup, create_process_group};
use crate::session::{Session, create_session};
use crate::thread::{Thread, create_thread};
use alloc::collections::BTreeMap;
use alloc::sync::{Arc, Weak};
use alloc::vec::Vec;
use core::sync::atomic::{AtomicBool, AtomicI32, AtomicU32, Ordering};
use spin::Mutex;

pub struct Process {
    pid: Pid,
    threads: Mutex<BTreeMap<Pid, Arc<Thread>>>,
    process_group: Mutex<Weak<ProcessGroup>>,
    children: Mutex<BTreeMap<Pid, Arc<Process>>>,
    parent: Mutex<Weak<Process>>,
    is_zombie: AtomicBool,
    exit_code: AtomicI32,
    // TODO: sub reaper
}

impl Process {
    pub fn get_pid(&self) -> Pid {
        self.pid
    }

    pub fn get_group(&self) -> Arc<ProcessGroup> {
        self.process_group.lock().upgrade().unwrap()
    }

    pub fn get_session(&self) -> Arc<Session> {
        self.get_group().get_session()
    }

    pub fn is_group_leader(&self) -> bool {
        self.get_group().get_pgid() == self.pid
    }

    pub fn is_session_leader(&self) -> bool {
        self.get_session().get_sid() == self.pid
    }

    fn change_group(self: &Arc<Self>, new_group: &Arc<ProcessGroup>) {
        let origin_group = self.get_group();
        origin_group.remove_process(self.pid);
        new_group.add_process(self.clone());
        *self.process_group.lock() = Arc::downgrade(&new_group);
    }

    /// Create a new process group if the current process is not the leader of a group
    /// Return the new process group, or the current process group if the current process is the leader
    pub fn create_group(self: &Arc<Self>) -> Arc<ProcessGroup> {
        let origin_group = self.get_group();
        if origin_group.get_pgid() == self.pid {
            // if current process is the leader of the group, return the current group
            return origin_group;
        }
        // create a new process group with current pid
        let new_group = create_process_group(self.pid, origin_group.session.clone());
        self.change_group(&new_group);
        new_group
    }

    pub fn move_to_group(self: &Arc<Self>, new_group: Pid) -> bool {
        if self.is_session_leader() {
            // session leader cannot move to another group
            return false;
        }
        let session = self.get_session();
        let new_group = session.get_process_group(new_group);
        if new_group.is_none() {
            // new group does not exist,
            // or attempts to move a process into a process group in a different session
            return false;
        }
        self.change_group(&new_group.unwrap());
        true
    }

    /// Create a new session if the current process is not the leader of a session.
    /// Current process will become the leader of the new session, and the process group leader of
    /// a new process group in the session.
    pub fn create_session(self: &Arc<Self>) -> Option<Arc<Session>> {
        if self.is_group_leader() {
            // if current process is the leader of the group, fails
            return None;
        }
        // create a new session with current pid
        let new_session = create_session(self.pid);
        let new_group = create_process_group(self.pid, Arc::downgrade(&new_session));
        self.change_group(&new_group);
        Some(new_session)
    }

    pub fn get_parent(&self) -> Option<Arc<Process>> {
        self.parent.lock().upgrade()
    }

    pub fn get_children(&self) -> Vec<Arc<Process>> {
        self.children.lock().values().cloned().collect()
    }

    pub fn get_child(&self, pid: Pid) -> Option<Arc<Process>> {
        self.children.lock().get(&pid).cloned()
    }

    /// only can be used in `create_process` function
    /// does nothing but initialize fields
    fn new(pid: Pid, parent: Weak<Process>, group: Weak<ProcessGroup>) -> Arc<Self> {
        Arc::new(Self {
            pid,
            threads: Mutex::new(BTreeMap::new()),
            process_group: Mutex::new(group),
            children: Mutex::new(BTreeMap::new()),
            parent: Mutex::new(parent),
            is_zombie: AtomicBool::new(false),
            exit_code: AtomicI32::new(0),
        })
    }

    /// only used to spawn a "newborn" process without parent, like `init` process
    pub fn spawn_process() -> Arc<Process> {
        let pid = generate_next_pid();
        let new_session = create_session(pid);
        let new_group = create_process_group(pid, Arc::downgrade(&new_session));
        create_process(pid, Weak::new(), Arc::downgrade(&new_group))
    }

    pub fn fork(self: &Arc<Self>) -> Arc<Process> {
        let pid = generate_next_pid();
        let new_group = self.get_group();
        let new_process = create_process(pid, Arc::downgrade(self), Arc::downgrade(&new_group));
        new_process
    }

    pub fn is_zombie(&self) -> bool {
        self.is_zombie.load(Ordering::Acquire)
    }

    fn set_zombie(&self) {
        self.is_zombie.store(true, Ordering::Release);
    }

    fn get_child_reaper(&self) -> Option<Arc<Process>> {
        // TODO: child reaper
        if self.pid == 1 {
            // TODO: check if the reaper is zombie
            return None;
        }
        PROCESS_TABLE.lock().get(&1).cloned()
    }

    pub(crate) fn exit(self: &Arc<Self>) {
        assert!(
            !self.is_zombie(),
            "[process] process {} is already exited",
            self.pid
        );
        self.set_zombie();
        // move children to reaper process
        let reaper = self.get_child_reaper();
        if let Some(reaper) = reaper {
            let mut children = self.children.lock();
            let mut reaper_children = reaper.children.lock();
            let weak_reaper = Arc::downgrade(&reaper);
            // `children` of the origin process will be cleared
            for (pid, child) in core::mem::take(&mut *children) {
                *child.parent.lock() = weak_reaper.clone();
                reaper_children.insert(pid, child);
            }
        }

        if self.get_parent().is_none() {
            // will become parentless zombie, release itself
            self.release();
        }
    }

    pub fn release(self: &Arc<Self>) {
        assert!(
            self.is_zombie(),
            "[process] process {} is not exited",
            self.pid
        );
        // TODO: remove threads
        // remove from parent
        if let Some(parent) = self.get_parent() {
            parent.children.lock().remove(&self.pid);
        }
        // remove from process group
        let group = self.get_group();
        group.remove_process(self.pid);
        // remove from process table
        PROCESS_TABLE.lock().remove(&self.pid);
    }

    pub(crate) fn add_thread(&self, thread: Arc<Thread>) {
        self.threads.lock().insert(thread.get_tid(), thread);
    }

    pub(crate) fn remove_thread(self: &Arc<Self>, tid: Pid, exit_code: i32) {
        self.threads.lock().remove(&tid);
        if self.threads.lock().is_empty() {
            self.exit_code.store(exit_code, Ordering::Relaxed);
            self.exit()
        }
    }

    pub fn create_thread(self: &Arc<Self>) -> Arc<Thread> {
        let tid = generate_next_pid();
        // `create_thread` will add the thread to the process
        create_thread(tid, Arc::downgrade(self))
    }

    pub fn get_main_thread(&self) -> Option<Arc<Thread>> {
        self.threads.lock().get(&self.pid).cloned()
    }

    pub fn get_threads(&self) -> Vec<Arc<Thread>> {
        self.threads.lock().values().cloned().collect()
    }

    pub fn get_exit_code(&self) -> i32 {
        assert!(self.is_zombie());
        self.exit_code.load(Ordering::Relaxed)
    }
}

static PROCESS_TABLE: Mutex<BTreeMap<Pid, Arc<Process>>> =
    Mutex::new(BTreeMap::<Pid, Arc<Process>>::new());

static NEXT_PID: AtomicU32 = AtomicU32::new(1);

fn generate_next_pid() -> Pid {
    NEXT_PID.fetch_add(1, Ordering::Acquire)
}

