use crate::Pid;
use crate::process::Process;
use alloc::collections::BTreeMap;
use alloc::sync::{Arc, Weak};
use spin::Mutex;

pub struct Thread {
    tid: Pid,
    process: Weak<Process>,
}

impl Thread {
    pub fn get_tid(&self) -> Pid {
        self.tid
    }

    pub fn get_process(&self) -> Arc<Process> {
        self.process.upgrade().unwrap()
    }

    /// Check if the thread is the main thread of the process.
    /// The "main thread" is also known as the "leader" of the thread group.
    /// If any of the threads in a thread group performs an execve,
    /// then all threads other than the thread group leader are terminated,
    /// and the new program is executed in the thread group leader.
    pub fn is_main_thread(&self) -> bool {
        self.tid == self.get_process().get_pid()
    }

    pub fn exit(self: &Arc<Self>, exit_code: i32) {
        self.get_process().remove_thread(self.tid, exit_code);
        THREAD_TABLE.lock().remove(&self.tid);
    }

    fn new(tid: Pid, process: Weak<Process>) -> Arc<Self> {
        Arc::new(Self { tid, process })
    }
}

static THREAD_TABLE: Mutex<BTreeMap<Pid, Arc<Thread>>> =
    Mutex::new(BTreeMap::<Pid, Arc<Thread>>::new());

/// Create a new thread if the thread does not exist
/// The new thread will be added to the process
pub(crate) fn create_thread(tid: Pid, process: Weak<Process>) -> Arc<Thread> {
    let mut thread_table = THREAD_TABLE.lock();
    if thread_table.contains_key(&tid) {
        panic!("[process] thread with id {} already exists", tid);
    }
    let thread = Thread::new(tid, process.clone());
    let process = process.upgrade().unwrap();
    process.add_thread(thread.clone());
    thread_table.insert(tid, thread.clone());
    thread
}

pub fn get_thread(tid: Pid) -> Option<Arc<Thread>> {
    let thread_table = THREAD_TABLE.lock();
    thread_table.get(&tid).cloned()
}

use crate::Pid;
use crate::process::Process;
use crate::session::Session;
use alloc::collections::BTreeMap;
use alloc::sync::{Arc, Weak};
use alloc::vec::Vec;
use spin::Mutex;

pub struct ProcessGroup {
    pgid: Pid,
    processes: Mutex<BTreeMap<Pid, Arc<Process>>>,
    pub(crate) session: Weak<Session>,
}

impl ProcessGroup {
    /// Get process group id
    pub fn get_pgid(&self) -> Pid {
        self.pgid
    }

    pub fn get_session(&self) -> Arc<Session> {
        self.session.upgrade().unwrap()
    }

    /// Get the leader process of the process group
    /// Return `None` if the leader process does not exist (maybe exited)
    pub fn get_leader(&self) -> Option<Arc<Process>> {
        // "leader" process is the process with the same id as the process group id
        self.processes.lock().get(&self.pgid).cloned()
    }

    pub fn add_process(&self, process: Arc<Process>) {
        self.processes.lock().insert(process.get_pid(), process);
    }

    pub fn remove_process(&self, pid: Pid) {
        self.processes.lock().remove(&pid);
        if self.processes.lock().is_empty() {
            // if the process group is empty, remove it from the session
            self.get_session().remove_process_group(self.pgid);
            // remove from the process group table
            PROCESS_GROUP_TABLE.lock().remove(&self.pgid);
        }
    }

    pub fn get_processes(&self) -> Vec<Arc<Process>> {
        self.processes.lock().values().cloned().collect()
    }

    /// Create a new process group with the given process group id and session
    fn new(id: Pid, session: Weak<Session>) -> Arc<Self> {
        Arc::new(Self {
            pgid: id,
            processes: Mutex::new(BTreeMap::new()),
            session,
        })
    }
}

static PROCESS_GROUP_TABLE: Mutex<BTreeMap<Pid, Arc<ProcessGroup>>> =
    Mutex::new(BTreeMap::<Pid, Arc<ProcessGroup>>::new());

/// Create a new process group if the process group does not exist
pub(crate) fn create_process_group(pgid: Pid, session: Weak<Session>) -> Arc<ProcessGroup> {
    let mut process_group_table = PROCESS_GROUP_TABLE.lock();
    if process_group_table.contains_key(&pgid) {
        panic!("[process] process group with id {} already exists", pgid);
    }
    let process_group = ProcessGroup::new(pgid, session.clone());
    let session = session.upgrade().unwrap();
    session.add_process_group(pgid, process_group.clone());
    process_group_table.insert(pgid, process_group.clone());
    process_group
}

pub fn get_process_group(pgid: Pid) -> Option<Arc<ProcessGroup>> {
    let process_group_table = PROCESS_GROUP_TABLE.lock();
    process_group_table.get(&pgid).cloned()
}

use crate::Pid;
use crate::process::Process;
use crate::process_group::ProcessGroup;
use alloc::collections::BTreeMap;
use alloc::sync::Arc;
use spin::Mutex;

pub struct Session {
    sid: Pid,
    process_groups: Mutex<BTreeMap<Pid, Arc<ProcessGroup>>>,
}

impl Session {
    /// Get session id
    pub fn get_sid(&self) -> Pid {
        self.sid
    }

    pub fn get_process_group(&self, pgid: Pid) -> Option<Arc<ProcessGroup>> {
        self.process_groups.lock().get(&pgid).cloned()
    }

    /// Get the leader process of the session
    /// Return `None` if the leader process does not exist (maybe exited)
    /// TODO
    pub fn get_leader(&self) -> Option<Arc<Process>> {
        // "leader" process is the process with the same id as the session id
        let process_group = self.process_groups.lock().get(&self.sid).cloned();
        process_group.and_then(|pg| pg.get_leader())
    }

    pub fn add_process_group(&self, pgid: Pid, process_group: Arc<ProcessGroup>) {
        self.process_groups.lock().insert(pgid, process_group);
    }

    pub fn remove_process_group(&self, pgid: Pid) {
        self.process_groups.lock().remove(&pgid);
        if self.process_groups.lock().is_empty() {
            // if the session is empty, remove it from the session table
            SESSION_TABLE.lock().remove(&self.sid);
        }
    }

    /// Create a new session with the given session id
    fn new(session_id: Pid) -> Arc<Self> {
        Arc::new(Self {
            sid: session_id,
            process_groups: Mutex::new(BTreeMap::new()),
        })
    }
}

static SESSION_TABLE: Mutex<BTreeMap<Pid, Arc<Session>>> =
    Mutex::new(BTreeMap::<Pid, Arc<Session>>::new());

/// Create a new session if the session does not exist
pub(crate) fn create_session(session_id: Pid) -> Arc<Session> {
    let mut session_table = SESSION_TABLE.lock();
    if session_table.contains_key(&session_id) {
        panic!("[process] session with id {} already exists", session_id);
    }
    let session = Session::new(session_id);
    session_table.insert(session_id, session.clone());
    session
}

pub fn get_session(session_id: Pid) -> Option<Arc<Session>> {
    SESSION_TABLE.lock().get(&session_id).cloned()
}

//! POSIX-like multitasking and process management.
//! Includes a strict two-level hierarchy of processes (session and process group).
//! See https://man7.org/linux/man-pages/man7/credentials.7.html for more details.
//! Session contain ProcessGroup, ProcessGroup contain Process, Process contain Thread.
//! Process has child processes.
#![no_std]

extern crate alloc;
pub mod process;
pub mod process_group;
pub mod session;
pub mod thread;

/// Type alias for session ID, process group ID, process ID, and thread ID.
/// Linux uses `int` for these IDs, which is typically 32 bits.
pub type Pid = u32;

use crate::core::file::fd::FD_TABLE;
use alloc::string::ToString;
use alloc::sync::Arc;
use axerrno::{LinuxError, LinuxResult};
use axfs_ng::api::FS_CONTEXT;
use axhal::arch::UspaceContext;
use axsignal::Signo;
use axtask::current;
use bitflags::bitflags;
use core::sync::atomic::Ordering;
use linux_raw_sys::general::*;
use spin::Mutex;
use starry_core::mm::copy_from_kernel;
use starry_core::process::{ProcessData, create_thread_data, get_process_data};
use starry_core::task::{
    TaskExt, create_user_task, current_process, current_process_data, read_trapframe_from_kstack,
};

bitflags! {
    /// Options for use with [`sys_clone`].
    #[derive(Debug, Clone, Copy, Default)]
    pub struct CloneFlags: u32 {
        /// The calling process and the child process run in the same
        /// memory space.
        const VM = CLONE_VM;
        /// The caller and the child process share the same  filesystem
        /// information.
        const FS = CLONE_FS;
        /// The calling process and the child process share the same file
        /// descriptor table.
        const FILES = CLONE_FILES;
        /// The calling process and the child process share the same table
        /// of signal handlers.
        const SIGHAND = CLONE_SIGHAND;
        /// If the calling process is being traced, then trace the child
        /// also.
        const PTRACE = CLONE_PTRACE;
        /// The execution of the calling process is suspended until the
        /// child releases its virtual memory resources via a call to
        /// execve(2) or _exit(2) (as with vfork(2)).
        const VFORK = CLONE_VFORK;
        /// The parent of the new child  (as returned by getppid(2))
        /// will be the same as that of the calling process.
        const PARENT = CLONE_PARENT;
        /// The child is placed in the same thread group as the calling
        /// process.
        const THREAD = CLONE_THREAD;
        /// The cloned child is started in a new mount namespace.
