const OS_NAME: &str = "UndefinedOS";
const OS_VERSION: &str = "10.0.0";

#[repr(C)]
pub struct UtsName {
    /// sysname
    pub sysname: [u8; 65],
    /// nodename
    pub nodename: [u8; 65],
    /// release
    pub release: [u8; 65],
    /// version
    pub version: [u8; 65],
    /// machine
    pub machine: [u8; 65],
    /// domainname
    pub domainname: [u8; 65],
}

impl Default for UtsName {
    fn default() -> Self {
        Self {
            sysname: Self::from_str(OS_NAME),
            nodename: Self::from_str("UndefinedOS-DESKTOP"),
            release: Self::from_str(OS_VERSION),
            version: Self::from_str(OS_VERSION),
            machine: Self::from_str(option_env!("ARCH").unwrap_or("riscv64")),
            domainname: Self::from_str("localdomain"),
        }
    }
}

impl UtsName {
    fn from_str(info: &str) -> [u8; 65] {
        let mut data: [u8; 65] = [0; 65];
        data[..info.len()].copy_from_slice(info.as_bytes());
        data
    }
}

pub fn sys_uname(name: UserPtr<UtsName>) -> LinuxResult<isize> {
    unsafe { *name.get()? = UtsName::default() };
    Ok(0)
}

use axerrno::{LinuxError, LinuxResult};
use axhal::mem::virt_to_phys;
use axhal::paging::{MappingFlags, PageSize};
use bitflags::bitflags;
use core::ffi::{c_int, c_ulong};
use memory_addr::{PAGE_SIZE_4K, VirtAddr, VirtAddrRange, align_down_4k, is_aligned_4k};
use starry_core::shared_memory::SHARED_MEMORY_MANAGER;
use starry_core::task::current_process_data;
use syscall_trace::syscall_trace;

bitflags! {
    struct ShmFlags: c_int {
        const IPC_CREAT = 0o1000;
        const IPC_EXCL = 0o2000;
        const IPC_NOWAIT = 0o4000;
        const SHM_RDONLY = 0o10000;
        const SHM_RND = 0o20000;
        const SHM_REMAP = 0o40000;
        const SHM_EXEC = 0o100000;
    }
}

const IPC_PRIVATE: c_int = 0;

#[syscall_trace]
pub fn sys_shmget(key: c_int, size: c_ulong, shm_flag: c_int) -> LinuxResult<isize> {
    let size = size as usize;
    let flags = ShmFlags::from_bits_truncate(shm_flag);
    // TODO: permission check
    if key == IPC_PRIVATE {
        // IPC get private
        // TODO: differentiate the caller of shm
        if SHARED_MEMORY_MANAGER.mem_map.lock().len() > 4096 {
            return Err(LinuxError::ENOSPC);
        }
        if size == 0 {
            return Err(LinuxError::EINVAL);
        }
        let key = SHARED_MEMORY_MANAGER.next_available_key();
        let shared_memory = SHARED_MEMORY_MANAGER.create(key, size)?;
        Ok(shared_memory.key as _)
    } else {
        let key = key as u32;
        if SHARED_MEMORY_MANAGER.get(key).is_none() {
            if !flags.contains(ShmFlags::IPC_CREAT) {
                Err(LinuxError::ENOENT)
            } else {
                // TODO: differentiate the caller of shm
                if SHARED_MEMORY_MANAGER.mem_map.lock().len() > 4096 {
                    return Err(LinuxError::ENOSPC);
                }
                if size == 0 {
                    return Err(LinuxError::EINVAL);
                }
                let shared_memory = SHARED_MEMORY_MANAGER.create(key, size)?;
                Ok(shared_memory.key as _)
            }
        } else {
            if flags.contains(ShmFlags::IPC_CREAT | ShmFlags::IPC_EXCL) {
                Err(LinuxError::EEXIST)
            } else {
                Ok(key as _)
            }
        }
    }
}

#[syscall_trace]
pub fn sys_shmat(shm_id: c_int, shm_addr: c_ulong, shm_flag: c_int) -> LinuxResult<isize> {
    let flags = ShmFlags::from_bits_truncate(shm_flag);
    let key = shm_id as u32;
    let shared_memory = SHARED_MEMORY_MANAGER.get(key).ok_or(LinuxError::EINVAL)?;
    let size = shared_memory.page_count * PAGE_SIZE_4K;
    let process_data = current_process_data();
    let mut addr_space = process_data.addr_space.lock();
    let addr = if shm_addr == 0 {
        addr_space.find_free_area(
            addr_space.base(),
            size,
            VirtAddrRange::new(addr_space.base(), addr_space.end()),
            PageSize::Size4K,
        )
    } else {
        if flags.contains(ShmFlags::SHM_RND) {
            let addr = align_down_4k(shm_addr as usize);
            addr_space.find_free_area(
                VirtAddr::from(addr),
                size,
                VirtAddrRange::new(addr_space.base(), addr_space.end()),
                PageSize::Size4K,
            )
        } else {
            if !is_aligned_4k(shm_addr as _) {
                return Err(LinuxError::EINVAL);
            }
            Some(VirtAddr::from(shm_addr as usize))
        }
    };
    let addr = addr.ok_or(LinuxError::ENOMEM)?;
    // permission
    let mut permission = MappingFlags::USER | MappingFlags::READ;
    if !flags.contains(ShmFlags::SHM_RDONLY) {
        permission |= MappingFlags::WRITE;
    }
    if flags.contains(ShmFlags::SHM_EXEC) {
        permission |= MappingFlags::EXECUTE;
    }
    let paddr = virt_to_phys(VirtAddr::from(shared_memory.addr));
    addr_space.map_linear(addr, paddr, size, permission, PageSize::Size4K)?;
    // add to process data
    let process_data = current_process_data();
    let mut process_shared_memory = process_data.shared_memory.lock();
    process_shared_memory.insert(addr, shared_memory);

    Ok(addr.as_usize() as _)
}

#[syscall_trace]
pub fn sys_shmctl(shm_id: c_int, op: c_int, buf: c_ulong) -> LinuxResult<isize> {
    let key = shm_id as u32;
    let shared_memory = SHARED_MEMORY_MANAGER.get(key).ok_or(LinuxError::EINVAL)?;
    match op {
        0 => {
            // IPC_RMID
            if SHARED_MEMORY_MANAGER.delete(shared_memory.key) {
                Ok(0)
            } else {
                Err(LinuxError::EINVAL)
            }
        }
        1 => {
            // IPC_STAT
            // let buf: UserOutPtr<shmid_ds> = (buf as usize).into();
            // let stat = buf.get_as_mut_ref()?;
            // stat.shm_perm.__key = shared_memory.key as _;
            // stat.shm_perm.mode = 0o600;
            // stat.shm_perm.cuid = 1000;
            // stat.shm_perm.uid = 1000;
            // stat.shm_perm.gid = 1000;
            // stat.shm_perm.cgid = 1000;
            // stat.shm_perm.__seq = 0;
            // stat.shm_segsz = shared_memory.page_count * PAGE_SIZE_4K;
            // Ok(0)
            Err(LinuxError::ENOSYS)
        }
        _ => Err(LinuxError::EINVAL),
    }
}

#[syscall_trace]
pub fn sys_shmdt(shm_addr: c_ulong) -> LinuxResult<isize> {
    let process_data = current_process_data();
    let mut shared_memory = process_data.shared_memory.lock();
    let virt_addr = VirtAddr::from(shm_addr as usize);
    let shm_to_detach = shared_memory.remove(&virt_addr).ok_or(LinuxError::EINVAL)?;
    let mut addr_space = process_data.addr_space.lock();
    let size = shm_to_detach.page_count * PAGE_SIZE_4K;
    addr_space.unmap(virt_addr, size)?;
    Ok(0)
}

use proc_macro::TokenStream;
use quote::quote;
use syn::{ItemFn, PathArguments, parse_macro_input};

#[proc_macro_attribute]
pub fn syscall_trace(_attr: TokenStream, item: TokenStream) -> TokenStream {
    let mut function = parse_macro_input!(item as ItemFn);
    let signature = &function.sig;
    let fn_name = &signature.ident;
    let fn_args: Vec<_> = signature
        .inputs
        .iter()
        .filter_map(|arg| {
            // 仅解析命名的函数参数（如 `x: i32`，跳过 `self` 或模式匹配参数）
            match arg {
                syn::FnArg::Typed(pat_type) => {
                    // 提取参数名（例如 `x`）
                    let arg_name = match &*pat_type.pat {
                        syn::Pat::Ident(pat_ident) => &pat_ident.ident,
                        _ => return None, // 跳过复杂模式（如元组解构）
                    };
                    if arg_name == "tf" {
                        return None; // 跳过 `tf` 参数 (trap frame)
                    }
                    // 提取参数类型（例如 `i32`）
                    let arg_type = &pat_type.ty;
                    Some((arg_name, arg_type))
                }
                _ => None, // 忽略 `self` 等特殊参数
            }
        })
        .collect();

    let arg_patterns_in: Vec<_> = fn_args
        .iter()
        .map(|(arg_name, arg_type)| match &***arg_type {
            syn::Type::Path(type_path) => {
                let outer_type = type_path.path.segments.last().unwrap();
                let type_name = &outer_type.ident;
                if type_name == "UserInPtr" || type_name == "UserInOutPtr" {
                    if let PathArguments::AngleBracketed(args) = &outer_type.arguments {
                        let inner_generic_argument = args.args.first().unwrap();
                        if let syn::GenericArgument::Type(inner_ty) = inner_generic_argument {
                            if let syn::Type::Path(inner_path) = inner_ty {
                                let inner_segment = inner_path.path.segments.last().unwrap();
                                if inner_segment.ident == "c_char" {
                                    return quote! { #arg_name.fmt_trace_as_str() };
                                }
                            }
                        }
                    }
                    quote! { #arg_name.fmt_trace_content() }
                } else if type_name == "UserOutPtr" {
                    quote! { #arg_name.fmt_trace() }
                } else {
                    quote! { #arg_name }
                }
            }
            _ => quote! { #arg_name },
        })
        .collect();

    let arg_patterns_out: Vec<_> = fn_args
        .iter()
        .map(|(arg_name, arg_type)| match &***arg_type {
            syn::Type::Path(type_path) => {
                let outer_type = type_path.path.segments.last().unwrap();
                let type_name = &outer_type.ident;
                if type_name == "UserInPtr"
                    || type_name == "UserOutPtr"
                    || type_name == "UserInOutPtr"
                {
                    if let PathArguments::AngleBracketed(args) = &outer_type.arguments {
                        let inner_generic_argument = args.args.first().unwrap();
                        if let syn::GenericArgument::Type(inner_ty) = inner_generic_argument {
                            if let syn::Type::Path(inner_path) = inner_ty {
                                let inner_segment = inner_path.path.segments.last().unwrap();
                                if inner_segment.ident == "c_char" {
                                    return quote! { #arg_name.fmt_trace_as_str() };
                                }
                            }
                        }
                    }
                    quote! { #arg_name.fmt_trace_content() }
                } else {
                    quote! { #arg_name }
                }
            }
            _ => quote! { #arg_name },
        })
        .collect();

    let arg_names: Vec<_> = fn_args.iter().map(|(name, _)| quote! { #name }).collect();
    let arg_list_pattern = arg_names
        .iter()
        .map(|name| format!("{} = {{}}", name.to_string()))
        .collect::<Vec<_>>()
        .join(", ");
    let format_pattern_in = format!("[syscall] <= {}({})", fn_name, arg_list_pattern);
    let format_pattern_out = format!("[syscall] => {}({}) = {{}}", fn_name, arg_list_pattern);

    let fn_body = &function.block;
    function.block = syn::parse2(quote! {{
        debug!(#format_pattern_in #(, #arg_patterns_in)*);

        let __result = (|| {
            #fn_body
        })();

        use alloc::format;

        let __linux_result = match __result {
            Ok(ref value) => {
                format!("{:?}", value)
            }
            Err(ref error) => {
                format!("{:?}", error)
            }
        };
        debug!(#format_pattern_out #(, #arg_patterns_out)*, __linux_result);
        __result
    }})
    .unwrap();
    quote! {
        #function
    }
    .into()
}

